// MARK: - Secure Token Storage

protocol TokenStorageProtocol {
    func saveAccessToken(_ token: String)
    func saveRefreshToken(_ token: String)
    func getAccessToken() -> String?
    func getRefreshToken() -> String?
    func clearTokens()
}

final class KeychainTokenStorage: TokenStorageProtocol {
    
    private let accessTokenKey = "com.example.app.accessToken"
    private let refreshTokenKey = "com.example.app.refreshToken"
    private let serviceName = "com.example.app"
    
    func saveAccessToken(_ token: String) {
        save(key: accessTokenKey, value: token)
    }
    
    func saveRefreshToken(_ token: String) {
        save(key: refreshTokenKey, value: token)
    }
    
    func getAccessToken() -> String? {
        return load(key: accessTokenKey)
    }
    
    func getRefreshToken() -> String? {
        return load(key: refreshTokenKey)
    }
    
    func clearTokens() {
        delete(key: accessTokenKey)
        delete(key: refreshTokenKey)
    }
    
    // MARK: - Private Keychain Helpers
    
    private func save(key: String, value: String) {
        guard let data = value.data(using: .utf8) else { return }
        
        delete(key: key)
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        
        let status = SecItemAdd(query as CFDictionary, nil)
        if status != errSecSuccess {
            print("[KeychainTokenStorage] Failed to save item: \(status)")
        }
    }
    
    private func load(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            return nil
        }
        
        return String(data: data, encoding: .utf8)
    }
    
    private func delete(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key
        ]
        
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - SSL Pinning Delegate

final class SSLPinningDelegate: NSObject, URLSessionDelegate {
    
    private let pinnedCertificateNames: [String]
    
    init(pinnedCertificateNames: [String] = []) {
        self.pinnedCertificateNames = pinnedCertificateNames
        super.init()
    }
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        guard !pinnedCertificateNames.isEmpty else {
            // If no pinned certs configured, use default validation
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        let pinnedCertificates: [SecCertificate] = pinnedCertificateNames.compactMap { name in
            guard let certURL = Bundle.main.url(forResource: name, withExtension: "cer"),
                  let certData = try? Data(contentsOf: certURL),
                  let certificate = SecCertificateCreateWithData(nil, certData as CFData) else {
                return nil
            }
            return certificate
        }
        
        SecTrustSetAnchorCertificates(serverTrust, pinnedCertificates as CFArray)
        SecTrustSetAnchorCertificatesOnly(serverTrust, true)
        
        var error: CFError?
        let isTrusted = SecTrustEvaluateWithError(serverTrust, &error)
        
        if isTrusted {
            completionHandler(.useCredential, URLCredential(trust: serverTrust))
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
}

// MARK: - Network Client Protocol

protocol NetworkClientProtocol {
    func request<T: Decodable>(
        endpoint: APIEndpoint,
        body: Encodable?,
        queryParameters: [String: String]?,
        responseType: T.Type
    ) async throws -> T
}

// MARK: - Network Client

final class NetworkClient: NetworkClientProtocol {
    
    static let shared = NetworkClient()
    
    private let environment: Environment
    private let tokenStorage: TokenStorageProtocol
    private let session: URLSession
    private let sslPinningDelegate: SSLPinningDelegate
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder
    
    private let tokenRefreshLock = NSLock()
    private var isRefreshingToken = false
    
    init(
        environment: Environment = .production,
        tokenStorage: TokenStorageProtocol = KeychainTokenStorage(),
        pinnedCertificateNames: [String] = []
    ) {
        self.environment = environment
        self.tokenStorage = tokenStorage
        self.sslPinningDelegate = SSLPinningDelegate(pinnedCertificateNames: pinnedCertificateNames)
        
        let configuration = URLSessionConfiguration.default
        configuration.timeoutIntervalForRequest = 30
        configuration.timeoutIntervalForResource = 60
        configuration.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        configuration.urlCache = nil
        configuration.requestCachePolicy = .reloadIgnoringLocalCacheData
        
        // Restrict to TLS 1.2+
        configuration.tlsMinimumSupportedProtocolVersion = .TLSv12
        
        self.session = URLSession(
            configuration: configuration,
            delegate: sslPinningDelegate,
            delegateQueue: nil
        )
        
        self.decoder = JSONDecoder()
        self.encoder = JSONEncoder()
    }
    
    // MARK: - Public Request Method
    
    func request<T: Decodable>(
        endpoint: APIEndpoint,
        body: Encodable? = nil,
        queryParameters: [String: String]? = nil,
        responseType: T.Type
    ) async throws -> T {
        let urlRequest = try buildRequest(
            endpoint: endpoint,
            body: body,
            queryParameters: queryParameters
        )
        
        return try await executeRequest(urlRequest, endpoint: endpoint, body: body, queryParameters: queryParameters, responseType: responseType)
    }
    
    // MARK: - Private Helpers
    
    private func buildRequest(
        endpoint: APIEndpoint,
        body: Encodable?,
        queryParameters: [String: String]?
    ) throws -> URLRequest {
        var urlString = environment.baseURL + endpoint.path
        
        if let queryParameters = queryParameters, !queryParameters.isEmpty {
            guard var components = URLComponents(string: urlString) else {
                throw NetworkError.invalidURL
            }
            components.queryItems = queryParameters.map {
                URLQueryItem(name: $0.key, value: $0.value)
            }
            guard let finalURL = components.url else {
                throw NetworkError.invalidURL
            }
            urlString = finalURL.absoluteString
        }
        
        guard let url = URL(string: urlString) else {
            throw NetworkError.invalidURL
        }
        
        // Validate scheme is HTTPS
        guard url.scheme == "https" else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = endpoint.method.rawValue
        request.cachePolicy = .reloadIgnoringLocalCacheData
        
        if endpoint.requiresAuth {
            guard let token = tokenStorage.getAccessToken() else {
                throw NetworkError.unauthorized
            }
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        if let body = body {
            request.httpBody = try encoder.encode(AnyEncodable(body))
        }
        
        return request
    }
    
    private func executeRequest<T: Decodable>(
        _ request: URLRequest,
        endpoint: APIEndpoint,
        body: Encodable?,
        queryParameters: [String: String]?,
        responseType: T.Type,
        isRetry: Bool = false
    ) async throws -> T {
        let data: Data
        let response: URLResponse
        
        do {
            (data, response) = try await session.data(for: request)
        } catch let urlError as URLError {
            if urlError.code == .notConnectedToInternet || urlError.code == .networkConnectionLost {
                throw NetworkError.networkUnavailable
            }
            throw NetworkError.requestFailed(urlError)
        } catch {
            throw NetworkError.requestFailed(error)
        }
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw NetworkError.invalidResponse
        }
        
        switch httpResponse.statusCode {
        case 200...299:
            do {
                let decoded = try decoder.decode(T.self, from: data)
                return decoded
            } catch {
                throw NetworkError.decodingError(error)
            }
            
        case 401:
            if !isRetry && endpoint.requiresAuth {
                try await refreshAccessToken()
                let retryRequest = try buildRequest(
                    endpoint: endpoint,
                    body: body,
                    queryParameters: queryParameters
                )
                return try await executeRequest(
                    retryRequest,
                    endpoint: endpoint,
                    body: body,
                    queryParameters: queryParameters,
                    responseType: responseType,
                    isRetry: true
                )
            }
            tokenStorage.clearTokens()
            throw NetworkError.unauthorized
            
        case 429:
            throw NetworkError.rateLimited
            
        default:
            let errorMessage = parseErrorMessage(from: data)
            throw NetworkError.serverError(statusCode: httpResponse.statusCode, message: errorMessage)
        }
    }
    
    private func parseErrorMessage(from data: Data) -> String? {
        let errorResponse = try? decoder.decode(APIErrorResponse.self, from: data)
        return errorResponse?.message ?? errorResponse?.error
    }
    
    private func refreshAccessToken() async throws {
        tokenRefreshLock.lock()
        guard !isRefreshingToken else {
            tokenRefreshLock.unlock()
            // Wait briefly for the other refresh to complete
            try await Task.sleep(nanoseconds: 500_000_000)
            return
        }
        isRefreshingToken = true
        tokenRefreshLock.unlock()
        
        defer {
            tokenRefreshLock.lock()
            isRefreshingToken = false
            tokenRefreshLock.unlock()
        }
        
        guard let refreshToken = tokenStorage.getRefreshToken() else {
            tokenStorage.clearTokens()
            throw NetworkError.unauthorized
        }
        
        let refreshRequest = RefreshTokenRequest(refreshToken: refreshToken)
        let urlRequest = try buildRefreshRequest(body: refreshRequest)
        
        let data: Data
        let response: URLResponse
        
        do {
            (data, response) = try await session.data(for: urlRequest)
        } catch {
            tokenStorage.clearTokens()
            throw NetworkError.unauthorized
        }
        
        guard let httpResponse = response as? HTTPURLResponse,
              httpResponse.statusCode == 200 else {
            tokenStorage.clearTokens()
            throw NetworkError.unauthorized
        }
        
        do {
            let refreshResponse = try decoder.decode(RefreshTokenResponse.self, from: data)
            tokenStorage.saveAccessToken(refreshResponse.accessToken)
        } catch {
            tokenStorage.clearTokens()
            throw NetworkError.unauthorized
        }
    }
    
    private func buildRefreshRequest(body: RefreshTokenRequest) throws -> URLRequest {
        let urlString = environment.baseURL + APIEndpoint.refreshToken.path
        guard let url = URL(string: urlString), url.scheme == "https" else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = HTTPMethod.post.rawValue
        request.httpBody = try encoder.encode(body)
        return request
    }
}

// MARK: - AnyEncodable Wrapper

private struct AnyEncodable: Encodable {
    private let encodeClosure: (Encoder) throws -> Void
    
    init(_ wrapped: Encodable) {
        self.encodeClosure = { encoder in
            try wrapped.encode(to: encoder)
        }
    }
    
    func encode(to encoder: Encoder) throws {
        try encodeClosure(encoder)
    }
}

// MARK: - Auth Service

protocol AuthServiceProtocol {
    func login(email: String, password: String) async throws -> User
    func register(email: String, password: String) async throws -> User
    func logout()
}

final class AuthService: AuthServiceProtocol {
    
    private let networkClient: NetworkClientProtocol
    private let tokenStorage: TokenStorageProtocol
    
    init(
        networkClient: NetworkClientProtocol = NetworkClient.shared,
        tokenStorage: TokenStorageProtocol = KeychainTokenStorage()
    ) {
        self.networkClient = networkClient
        self.tokenStorage = tokenStorage
    }
    
    func login(email: String, password: String) async throws -> User {
        let sanitizedEmail = email.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        
        guard isValidEmail(sanitizedEmail) else {
            throw NetworkError.invalidURL
        }
        
        let authRequest = AuthRequest(email: sanitizedEmail, password: password)
        
        let response = try await networkClient.request(
            endpoint: .login,
            body: authRequest,
            queryParameters: nil,
            responseType: AuthResponse.self
        )
        
        tokenStorage.saveAccessToken(response.accessToken)
        tokenStorage.saveRefreshToken(response.refreshToken)
        
        return response.user
    }
    
    func register(email: String, password: String) async throws -> User {
        let sanitizedEmail = email.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        
        guard isValidEmail(sanitizedEmail) else {
            throw NetworkError.invalidURL
        }
        
        guard isValidPassword(password) else {
            throw NetworkError.serverError(statusCode: 400, message: "Password must be at least 8 characters")
        }
        
        let authRequest = AuthRequest(email: sanitizedEmail, password: password)
        
        let response = try await networkClient.request(
            endpoint: .register,
            body: authRequest,
            queryParameters: nil,
            responseType: AuthResponse.self
        )
        
        tokenStorage.saveAccessToken(response.accessToken)
        tokenStorage.saveRefreshToken(response.refreshToken)
        
        return response.user
    }
    
    func logout() {
        tokenStorage.clearTokens()
    }
    
    // MARK: - Validation
    
    private func isValidEmail(_ email: String) -> Bool {
        let emailRegex = #"^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$"#
        return email.range(of: emailRegex, options: .regularExpression) != nil
    }
    
    private func isValidPassword(_ password: String) -> Bool {
        return password.count >= 8
    }
}

// MARK: - User Service

protocol UserServiceProtocol {
    func fetchCurrentUser() async throws -> User
    func fetchUsers(page: Int, limit: Int) async throws -> UsersResponse
    func fetchUser(id: String) async throws -> User
}

final class UserService: UserServiceProtocol {
    
    private let networkClient: NetworkClientProtocol
    
    init(networkClient: NetworkClientProtocol = NetworkClient.shared) {
        self.networkClient = networkClient
    }
    
    func fetchCurrentUser() async throws -> User {
        return try await networkClient.request(
            endpoint: .userProfile,
            body: nil,
            queryParameters: nil,
            responseType: User.self
        )
    }
    
    func fetchUsers(page: Int = 1, limit: Int = 20) async throws -> UsersResponse {
        let clampedLimit = min(max(limit, 1), 100)
        let clampedPage = max(page, 1)
        
        let queryParams = [
            "page": String(clampedPage),
            "limit": String(clampedLimit)
        ]
        
        return try await networkClient.request(
            endpoint: .users,
            body: nil,
            queryParameters: queryParams,
            responseType: UsersResponse.self
        )
    }
    
    func fetchUser(id: String) async throws -> User {
        let sanitizedId = id.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !sanitizedId.isEmpty else {
            throw NetworkError.invalidURL
        }
        
        return try await networkClient.request(
            endpoint: .user(id: sanitizedId),
            body: nil,
            queryParameters: nil,
            responseType: User.self
        )
    }
}

